'use client';

import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { useAlert } from '@/lib/use-alert';
import { useConfirm } from '@/lib/use-confirm';
import { Download, GraduationCap, Plus, Save, Trash2 } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';

interface Teacher {
  id: number;
  email: string;
  name?: string;
  first_name?: string;
  last_name?: string;
  subject?: string;
  subjects?: string;
  specialization?: string;
  [key: string]: any;
}

export default function TeacherGrades() {
  const router = useRouter();
  const [teacher, setTeacher] = useState<Teacher | null>(null);
  const [selectedSection, setSelectedSection] = useState('Section A');
  const [selectedQuarter, setSelectedQuarter] = useState('Q1');
  const [gradesData, setGradesData] = useState<any[]>([]);
  const [isSavingGrades, setIsSavingGrades] = useState(false);
  const [isLoadingData, setIsLoadingData] = useState(false);
  const [showAddStudentDialog, setShowAddStudentDialog] = useState(false);
  const [selectedStudentId, setSelectedStudentId] = useState('');
  const [availableStudents, setAvailableStudents] = useState<any[]>([]);
  const [isAddingStudent, setIsAddingStudent] = useState(false);
  const { showAlert } = useAlert();
  const { showConfirm } = useConfirm();

  // Get grading weights based on subject type
  const getGradingWeights = (subject: string) => {
    const subjectLower = subject?.toLowerCase() || '';

    // Group 1: Filipino/English/AP/ESP/MT
    if (
      subjectLower.includes('filipino') ||
      subjectLower.includes('english') ||
      subjectLower.includes('araling panlipunan') ||
      subjectLower.includes('ap') ||
      subjectLower.includes('esp') ||
      subjectLower.includes('edukasyon sa pagpapakatao') ||
      subjectLower.includes('mother tongue') ||
      subjectLower.includes('mt')
    ) {
      return {
        writtenWork: 30,
        performanceTasks: 50,
        quarterlyAssessment: 20,
      };
    }

    // Group 2: Science/Mathematics
    if (
      subjectLower.includes('science') ||
      subjectLower.includes('mathematics') ||
      subjectLower.includes('math')
    ) {
      return {
        writtenWork: 40,
        performanceTasks: 40,
        quarterlyAssessment: 20,
      };
    }

    // Group 3: MAPEH/EPP/TLE/ELECTIVE/WRITING
    if (
      subjectLower.includes('mapeh') ||
      subjectLower.includes('music') ||
      subjectLower.includes('arts') ||
      subjectLower.includes('physical education') ||
      subjectLower.includes('health') ||
      subjectLower.includes('epp') ||
      subjectLower.includes('tle') ||
      subjectLower.includes('technology') ||
      subjectLower.includes('livelihood') ||
      subjectLower.includes('elective') ||
      subjectLower.includes('writing')
    ) {
      return {
        writtenWork: 20,
        performanceTasks: 60,
        quarterlyAssessment: 20,
      };
    }

    // Default to Group 1 if subject not recognized
    return {
      writtenWork: 30,
      performanceTasks: 50,
      quarterlyAssessment: 20,
    };
  };

  // Calculate final grade for a student
  const calculateFinalGrade = (student: any) => {
    const teacherSubject =
      teacher?.subject || teacher?.subjects || 'Mathematics';
    const weights = getGradingWeights(teacherSubject);

    // Calculate Written Work average
    const writtenWorkScores = student.writtenWork
      .map((score: string) => parseFloat(score) || 0)
      .filter((score: number) => score > 0);
    const writtenWorkAvg =
      writtenWorkScores.length > 0
        ? writtenWorkScores.reduce((a: number, b: number) => a + b, 0) /
          writtenWorkScores.length
        : 0;

    // Calculate Performance Tasks average
    const performanceScores = student.performanceTasks
      .map((score: string) => parseFloat(score) || 0)
      .filter((score: number) => score > 0);
    const performanceAvg =
      performanceScores.length > 0
        ? performanceScores.reduce((a: number, b: number) => a + b, 0) /
          performanceScores.length
        : 0;

    // Quarterly Assessment
    const quarterlyScore = parseFloat(student.quarterlyAssessment) || 0;

    // Calculate weighted final grade
    const finalGrade =
      (writtenWorkAvg * weights.writtenWork) / 100 +
      (performanceAvg * weights.performanceTasks) / 100 +
      (quarterlyScore * weights.quarterlyAssessment) / 100;

    return finalGrade > 0 ? finalGrade.toFixed(2) : '';
  };

  // Update grade value
  const updateGrade = (
    studentId: number,
    category: string,
    index: number | null,
    value: string
  ) => {
    setGradesData((prev) =>
      prev.map((student) => {
        if (student.id === studentId) {
          if (index !== null) {
            // Array field (writtenWork or performanceTasks)
            const newArray = [...student[category]];
            newArray[index] = value;
            return { ...student, [category]: newArray };
          } else {
            // Single field (quarterlyAssessment)
            return { ...student, [category]: value };
          }
        }
        return student;
      })
    );
  };

  // Check if teacher is logged in
  useEffect(() => {
    const storedTeacher = localStorage.getItem('teacher');
    if (!storedTeacher) {
      router.push('/teacher/login');
      return;
    }

    try {
      const teacherData = JSON.parse(storedTeacher);
      setTeacher(teacherData);
    } catch (error) {
      console.error('Error parsing stored teacher data:', error);
      localStorage.removeItem('teacher');
      router.push('/teacher/login');
    }
  }, [router]);

  // Fetch available students for the dropdown
  useEffect(() => {
    const fetchAvailableStudents = async () => {
      if (!teacher || !teacher.id) return;

      try {
        const response = await fetch(
          `/api/students/all?teacherId=${teacher.id}`
        );
        const data = await response.json();
        if (data.success && data.students) {
          setAvailableStudents(data.students);
        }
      } catch (error) {
        console.error('Error fetching students:', error);
      }
    };

    fetchAvailableStudents();
  }, [teacher]);

  // Fetch real grades data
  useEffect(() => {
    if (teacher && teacher.id) {
      fetchGradesData();
    }
  }, [teacher, selectedSection, selectedQuarter]);

  const fetchGradesData = async () => {
    if (!teacher || !teacher.id) return;

    setIsLoadingData(true);
    try {
      const teacherSubject =
        teacher.subject ||
        teacher.subjects ||
        teacher.specialization ||
        'General';

      // Fetch detailed grades from teacher API
      const response = await fetch(
        `/api/teacher/grades?teacherId=${teacher.id}&section=${selectedSection}&subject=${encodeURIComponent(teacherSubject)}`
      );
      const data = await response.json();

      if (data.success && data.data) {
        setGradesData(data.data);

        // Also fetch final grades for each student from grades API
        const studentIds = data.data.map((student: any) => student.id);
        const gradePromises = studentIds.map(async (studentId: number) => {
          try {
            const gradeResponse = await fetch(
              `/api/grades?studentId=${studentId}`
            );
            const gradeData = await gradeResponse.json();

            if (gradeData.success && gradeData.grades) {
              // Find the grade for this subject
              const subjectGrade = gradeData.grades.find(
                (g: any) => g.subject === teacherSubject
              );
              return { studentId, finalGrade: subjectGrade?.grade };
            }
            return { studentId, finalGrade: null };
          } catch (error) {
            console.error(
              `Error fetching grade for student ${studentId}:`,
              error
            );
            return { studentId, finalGrade: null };
          }
        });

        const savedGrades = await Promise.all(gradePromises);
        console.log('Loaded saved final grades:', savedGrades);
      }
    } catch (error) {
      console.error('Error fetching grades:', error);
    } finally {
      setIsLoadingData(false);
    }
  };

  // Save grades
  const handleSaveGrades = async () => {
    if (!teacher || !teacher.id) {
      showAlert({ message: 'Teacher information not found', type: 'error' });
      return;
    }

    setIsSavingGrades(true);
    try {
      const teacherSubject =
        teacher.subject ||
        teacher.subjects ||
        teacher.specialization ||
        'General';

      // Save to teacher grades API (for detailed grading records)
      const teacherGradesResponse = await fetch('/api/teacher/grades', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          teacherId: teacher.id,
          subject: teacherSubject,
          section: selectedSection,
          quarter: selectedQuarter,
          grades: gradesData,
        }),
      });

      const teacherGradesData = await teacherGradesResponse.json();

      if (!teacherGradesData.success) {
        showAlert({
          message: teacherGradesData.error || 'Failed to save detailed grades',
          type: 'error',
        });
        return;
      }

      // Also save final grades to student grades API
      const gradePromises = gradesData.map(async (student) => {
        const finalGrade = calculateFinalGrade(student);
        if (!finalGrade) return { success: true }; // Skip if no grade calculated

        try {
          const response = await fetch('/api/grades', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              studentId: student.id,
              subject: teacherSubject,
              grade: parseFloat(finalGrade),
            }),
          });

          return await response.json();
        } catch (error) {
          console.error(`Error saving grade for student ${student.id}:`, error);
          return { success: false };
        }
      });

      const gradeResults = await Promise.all(gradePromises);
      const failedGrades = gradeResults.filter((r) => !r.success);

      if (failedGrades.length > 0) {
        showAlert({
          message: `Grades saved, but ${failedGrades.length} final grade(s) failed to update`,
          type: 'warning',
        });
      } else {
        showAlert({
          message: 'All grades saved successfully!',
          type: 'success',
        });
      }
    } catch (error) {
      console.error('Error saving grades:', error);
      showAlert({
        message: 'Error saving grades. Please try again.',
        type: 'error',
      });
    } finally {
      setIsSavingGrades(false);
    }
  };

  const handleAddStudent = async () => {
    if (!selectedStudentId) {
      showAlert({
        message: 'Please select a student.',
        type: 'error',
      });
      return;
    }

    // Find the selected student from availableStudents
    const student = availableStudents.find((s) => s.id === selectedStudentId);
    if (!student) {
      showAlert({
        message: 'Student not found.',
        type: 'error',
      });
      return;
    }

    // Check if student already exists in this section
    const exists = gradesData.some((s) => s.id === student.id);
    if (exists) {
      showAlert({
        message: 'Student already exists in this section.',
        type: 'error',
      });
      return;
    }

    if (!teacher || !teacher.id) {
      showAlert({ message: 'Teacher information not found', type: 'error' });
      return;
    }

    setIsAddingStudent(true);

    try {
      const teacherSubject =
        teacher.subject ||
        teacher.subjects ||
        teacher.specialization ||
        'General';

      const newStudentData = {
        id: student.id,
        name: `${student.first_name} ${student.last_name}`,
        studentNumber: student.student_number,
        writtenWork: ['', '', '', '', ''],
        performanceTasks: ['', '', '', '', ''],
        quarterlyAssessment: '',
      };

      // Optimistically add to UI
      setGradesData([...gradesData, newStudentData]);
      setSelectedStudentId('');
      setShowAddStudentDialog(false);

      // Save to database immediately
      const response = await fetch('/api/teacher/grades', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          teacherId: teacher.id,
          subject: teacherSubject,
          section: selectedSection,
          quarter: selectedQuarter,
          grades: [...gradesData, newStudentData],
        }),
      });

      const data = await response.json();

      if (data.success) {
        showAlert({
          message: `${newStudentData.name} added successfully!`,
          type: 'success',
        });
        // Refresh grades data
        await fetchGradesData();
      } else {
        // Revert if failed
        setGradesData(gradesData);
        showAlert({
          message: data.error || 'Failed to add student.',
          type: 'error',
        });
      }
    } catch (error) {
      console.error('Error adding student:', error);
      // Revert on error
      setGradesData(gradesData);
      showAlert({
        message: 'Error adding student. Please try again.',
        type: 'error',
      });
    } finally {
      setIsAddingStudent(false);
    }
  };

  // Delete student
  const handleDeleteStudent = async (
    studentId: number,
    studentName: string
  ) => {
    const confirmed = await showConfirm({
      message: `Are you sure you want to remove ${studentName} from this grading sheet?`,
      confirmText: 'Delete',
      cancelText: 'Cancel',
      variant: 'destructive',
    });

    if (confirmed) {
      if (!teacher || !teacher.id) {
        showAlert({ message: 'Teacher information not found', type: 'error' });
        return;
      }

      const teacherSubject =
        teacher.subject ||
        teacher.subjects ||
        teacher.specialization ||
        'General';

      // Remove from local state optimistically
      const updatedGrades = gradesData.filter((s) => s.id !== studentId);
      setGradesData(updatedGrades);

      try {
        // Save updated list to database
        const response = await fetch('/api/teacher/grades', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            teacherId: teacher.id,
            subject: teacherSubject,
            section: selectedSection,
            quarter: selectedQuarter,
            grades: updatedGrades,
          }),
        });

        const data = await response.json();

        if (data.success) {
          showAlert({
            message: 'Student removed successfully!',
            type: 'success',
          });
        } else {
          // Revert if failed
          setGradesData(gradesData);
          showAlert({
            message: data.error || 'Failed to remove student.',
            type: 'error',
          });
        }
      } catch (error) {
        console.error('Error removing student:', error);
        // Revert on error
        setGradesData(gradesData);
        showAlert({
          message: 'Error removing student. Please try again.',
          type: 'error',
        });
      }
    }
  };

  // Export grades to CSV
  const handleExportToCSV = () => {
    if (!teacher || gradesData.length === 0) {
      showAlert({ message: 'No grades data to export.', type: 'warning' });
      return;
    }

    const teacherSubject = teacher.subject || teacher.subjects || 'Mathematics';
    const weights = getGradingWeights(teacherSubject);

    // Create CSV header
    const headers = [
      'Student Number',
      'Student Name',
      'WW1',
      'WW2',
      'WW3',
      'WW4',
      'WW5',
      'PT1',
      'PT2',
      'PT3',
      'PT4',
      'PT5',
      'Quarterly Assessment',
      'Final Grade',
    ];

    // Create CSV rows
    const rows = gradesData.map((student) => {
      const finalGrade = calculateFinalGrade(student);
      return [
        student.studentNumber || '',
        student.name || '',
        ...student.writtenWork,
        ...student.performanceTasks,
        student.quarterlyAssessment || '',
        finalGrade || '',
      ];
    });

    // Combine header and rows
    const csvContent = [headers, ...rows]
      .map((row) => row.map((cell) => `"${cell}"`).join(','))
      .join('\n');

    // Create download link
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute(
      'download',
      `${teacherSubject}_${selectedSection}_${selectedQuarter}_grades.csv`
    );
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    showAlert({
      message: 'Grades exported successfully!',
      type: 'success',
    });
  };

  return (
    <div className="container mx-auto p-6 space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="text-red-800">
            Student Grades Management
          </CardTitle>
          <CardDescription>
            View and update student grades for your classes
          </CardDescription>
        </CardHeader>
        <CardContent>
          {teacher ? (
            <div className="space-y-6">
              {/* Filters and Actions */}
              <div className="flex flex-wrap items-center gap-4 pb-4 border-b">
                <div className="flex items-center gap-2">
                  <Label
                    htmlFor="section-select"
                    className="text-sm font-medium"
                  >
                    Section:
                  </Label>
                  <Select
                    value={selectedSection}
                    onValueChange={setSelectedSection}
                  >
                    <SelectTrigger id="section-select" className="w-40">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Section A">Section A</SelectItem>
                      <SelectItem value="Section B">Section B</SelectItem>
                      <SelectItem value="Section C">Section C</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="flex items-center gap-2">
                  <Label
                    htmlFor="quarter-select"
                    className="text-sm font-medium"
                  >
                    Quarter:
                  </Label>
                  <Select
                    value={selectedQuarter}
                    onValueChange={setSelectedQuarter}
                  >
                    <SelectTrigger id="quarter-select" className="w-32">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Q1">Q1</SelectItem>
                      <SelectItem value="Q2">Q2</SelectItem>
                      <SelectItem value="Q3">Q3</SelectItem>
                      <SelectItem value="Q4">Q4</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="ml-auto flex items-center gap-2">
                  <Badge variant="outline" className="text-sm">
                    Subject:{' '}
                    {teacher.subject ||
                      teacher.subjects ||
                      teacher.specialization ||
                      'N/A'}
                  </Badge>
                  {/* Add Student Button */}
                  <Dialog
                    open={showAddStudentDialog}
                    onOpenChange={setShowAddStudentDialog}
                  >
                    <DialogTrigger asChild>
                      <Button
                        size="sm"
                        className="bg-green-700 hover:bg-green-800"
                      >
                        <Plus className="w-4 h-4 mr-2" />
                        Add Student
                      </Button>
                    </DialogTrigger>
                    <DialogContent>
                      <DialogHeader>
                        <DialogTitle>Add Student to Grading Sheet</DialogTitle>
                        <DialogDescription>
                          Select a student to add to {selectedSection}
                        </DialogDescription>
                      </DialogHeader>
                      <div className="space-y-4 py-4">
                        <div className="space-y-2">
                          <Label htmlFor="student-select">Select Student</Label>
                          <Select
                            value={selectedStudentId}
                            onValueChange={setSelectedStudentId}
                            disabled={isAddingStudent}
                          >
                            <SelectTrigger id="student-select">
                              <SelectValue placeholder="Choose a student" />
                            </SelectTrigger>
                            <SelectContent>
                              {availableStudents
                                .filter(
                                  (student) =>
                                    !gradesData.some((s) => s.id === student.id)
                                )
                                .map((student) => (
                                  <SelectItem
                                    key={student.id}
                                    value={student.id}
                                  >
                                    {student.first_name} {student.last_name} (
                                    {student.student_number})
                                  </SelectItem>
                                ))}
                            </SelectContent>
                          </Select>
                          <p className="text-xs text-gray-500">
                            Only students not yet added to this section are
                            shown
                          </p>
                        </div>
                      </div>
                      <div className="flex justify-end gap-2">
                        <Button
                          variant="outline"
                          onClick={() => {
                            setShowAddStudentDialog(false);
                            setSelectedStudentId('');
                          }}
                          disabled={isAddingStudent}
                        >
                          Cancel
                        </Button>
                        <Button
                          onClick={handleAddStudent}
                          className="bg-green-700 hover:bg-green-800"
                          disabled={isAddingStudent}
                        >
                          {isAddingStudent ? 'Adding...' : 'Add Student'}
                        </Button>
                      </div>
                    </DialogContent>
                  </Dialog>
                </div>
              </div>

              {isLoadingData ? (
                <div className="text-center py-12">
                  <div className="text-xl font-bold text-red-800">
                    Loading grades data...
                  </div>
                </div>
              ) : gradesData.length === 0 ? (
                <div className="text-center py-12">
                  <GraduationCap className="w-16 h-16 text-gray-400 mx-auto mb-4" />
                  <p className="text-gray-600 mb-2">
                    No students found for {selectedSection}
                  </p>
                  <p className="text-sm text-gray-500">
                    Click "Add Student" to start adding students to the grading
                    sheet
                  </p>
                </div>
              ) : (
                <>
                  {/* Grading System Info */}
                  {(() => {
                    const teacherSubject =
                      teacher.subject ||
                      teacher.subjects ||
                      teacher.specialization ||
                      'Mathematics';
                    const weights = getGradingWeights(teacherSubject);
                    return (
                      <div className="bg-blue-50 p-4 rounded-lg border border-blue-200">
                        <div className="text-sm font-semibold text-blue-900 mb-2">
                          Grading System ({teacherSubject}):
                        </div>
                        <div className="grid grid-cols-3 gap-4 text-sm">
                          <div>
                            <span className="font-medium">Written Work: </span>
                            <span className="text-blue-700">
                              {weights.writtenWork}%
                            </span>
                          </div>
                          <div>
                            <span className="font-medium">
                              Performance Tasks:{' '}
                            </span>
                            <span className="text-blue-700">
                              {weights.performanceTasks}%
                            </span>
                          </div>
                          <div>
                            <span className="font-medium">
                              Quarterly Assessment:{' '}
                            </span>
                            <span className="text-blue-700">
                              {weights.quarterlyAssessment}%
                            </span>
                          </div>
                        </div>
                      </div>
                    );
                  })()}

                  {/* Spreadsheet-like Grades Table */}
                  <div className="overflow-x-auto border rounded-lg">
                    <Table>
                      <TableHeader>
                        <TableRow className="bg-red-800 text-white">
                          <TableHead className="text-white font-bold sticky left-0 bg-red-800 z-10 min-w-[50px]">
                            Action
                          </TableHead>
                          <TableHead className="text-white font-bold sticky left-[50px] bg-red-800 z-10 min-w-[150px]">
                            Student Name
                          </TableHead>
                          <TableHead className="text-white font-bold sticky left-[200px] bg-red-800 z-10 min-w-[100px]">
                            Student No.
                          </TableHead>
                          <TableHead
                            colSpan={5}
                            className="text-white font-bold text-center border-l-2 border-white"
                          >
                            Written Work (
                            {(() => {
                              const teacherSubject =
                                teacher.subject ||
                                teacher.subjects ||
                                'Mathematics';
                              return getGradingWeights(teacherSubject)
                                .writtenWork;
                            })()}
                            %)
                          </TableHead>
                          <TableHead
                            colSpan={5}
                            className="text-white font-bold text-center border-l-2 border-white"
                          >
                            Performance Tasks (
                            {(() => {
                              const teacherSubject =
                                teacher.subject ||
                                teacher.subjects ||
                                'Mathematics';
                              return getGradingWeights(teacherSubject)
                                .performanceTasks;
                            })()}
                            %)
                          </TableHead>
                          <TableHead className="text-white font-bold text-center border-l-2 border-white min-w-[120px]">
                            Quarterly Assessment (
                            {(() => {
                              const teacherSubject =
                                teacher.subject ||
                                teacher.subjects ||
                                'Mathematics';
                              return getGradingWeights(teacherSubject)
                                .quarterlyAssessment;
                            })()}
                            %)
                          </TableHead>
                          <TableHead className="text-white font-bold text-center border-l-2 border-white min-w-[100px]">
                            Final Grade
                          </TableHead>
                        </TableRow>
                        <TableRow className="bg-gray-100">
                          <TableHead className="sticky left-0 bg-gray-100 z-10"></TableHead>
                          <TableHead className="sticky left-[50px] bg-gray-100 z-10"></TableHead>
                          <TableHead className="sticky left-[200px] bg-gray-100 z-10"></TableHead>
                          {Array.from({ length: 5 }).map((_, i) => (
                            <TableHead
                              key={`ww-${i}`}
                              className="text-center text-xs border-l min-w-[80px]"
                            >
                              WW{i + 1}
                            </TableHead>
                          ))}
                          {Array.from({ length: 5 }).map((_, i) => (
                            <TableHead
                              key={`pt-${i}`}
                              className="text-center text-xs border-l min-w-[80px]"
                            >
                              PT{i + 1}
                            </TableHead>
                          ))}
                          <TableHead className="text-center text-xs border-l"></TableHead>
                          <TableHead className="text-center text-xs border-l"></TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {gradesData.map((student) => (
                          <TableRow
                            key={student.id}
                            className="hover:bg-gray-50"
                          >
                            <TableCell className="sticky left-0 bg-white z-10 border-r p-2">
                              <Button
                                size="sm"
                                variant="ghost"
                                onClick={() =>
                                  handleDeleteStudent(student.id, student.name)
                                }
                                className="h-8 w-8 p-0 text-red-600 hover:text-red-800 hover:bg-red-50"
                              >
                                <Trash2 className="w-4 h-4" />
                              </Button>
                            </TableCell>
                            <TableCell className="font-medium sticky left-[50px] bg-white z-10 border-r">
                              {student.name}
                            </TableCell>
                            <TableCell className="sticky left-[200px] bg-white z-10 border-r">
                              {student.studentNumber}
                            </TableCell>
                            {/* Written Work cells */}
                            {student.writtenWork.map(
                              (score: string, index: number) => (
                                <TableCell
                                  key={`ww-${student.id}-${index}`}
                                  className="p-0 border-l"
                                >
                                  <Input
                                    type="number"
                                    min="0"
                                    max="100"
                                    step="0.01"
                                    value={score}
                                    onChange={(e) =>
                                      updateGrade(
                                        student.id,
                                        'writtenWork',
                                        index,
                                        e.target.value
                                      )
                                    }
                                    className="border-0 rounded-none text-center focus:ring-2 focus:ring-red-500 h-10"
                                    placeholder="0"
                                  />
                                </TableCell>
                              )
                            )}
                            {/* Performance Tasks cells */}
                            {student.performanceTasks.map(
                              (score: string, index: number) => (
                                <TableCell
                                  key={`pt-${student.id}-${index}`}
                                  className="p-0 border-l"
                                >
                                  <Input
                                    type="number"
                                    min="0"
                                    max="100"
                                    step="0.01"
                                    value={score}
                                    onChange={(e) =>
                                      updateGrade(
                                        student.id,
                                        'performanceTasks',
                                        index,
                                        e.target.value
                                      )
                                    }
                                    className="border-0 rounded-none text-center focus:ring-2 focus:ring-red-500 h-10"
                                    placeholder="0"
                                  />
                                </TableCell>
                              )
                            )}
                            {/* Quarterly Assessment cell */}
                            <TableCell className="p-0 border-l">
                              <Input
                                type="number"
                                min="0"
                                max="100"
                                step="0.01"
                                value={student.quarterlyAssessment}
                                onChange={(e) =>
                                  updateGrade(
                                    student.id,
                                    'quarterlyAssessment',
                                    null,
                                    e.target.value
                                  )
                                }
                                className="border-0 rounded-none text-center focus:ring-2 focus:ring-red-500 h-10"
                                placeholder="0"
                              />
                            </TableCell>
                            {/* Final Grade cell */}
                            <TableCell className="text-center font-bold text-red-800 border-l bg-gray-50">
                              {calculateFinalGrade(student) || '-'}
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>

                  {/* Save and Export Buttons */}
                  <div className="flex justify-end gap-3">
                    <Button
                      onClick={handleExportToCSV}
                      variant="outline"
                      className="border-red-800 text-red-800 hover:bg-red-50"
                    >
                      <Download className="w-4 h-4 mr-2" />
                      Export to CSV
                    </Button>
                    <Button
                      onClick={handleSaveGrades}
                      disabled={isSavingGrades}
                      className="bg-red-800 hover:bg-red-900"
                    >
                      {isSavingGrades ? (
                        <>
                          <Save className="w-4 h-4 mr-2 animate-spin" />
                          Saving...
                        </>
                      ) : (
                        <>
                          <Save className="w-4 h-4 mr-2" />
                          Save Grades
                        </>
                      )}
                    </Button>
                  </div>
                </>
              )}
            </div>
          ) : (
            <div className="text-center py-12">
              <GraduationCap className="w-16 h-16 text-gray-400 mx-auto mb-4" />
              <p className="text-gray-600">Please log in to manage grades.</p>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
